import argparse
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions, replication_factor, configurations):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, configs=configurations)
    admin_client.create_topics(new_topics=[topic])

def increase_partition(admin_client, topic_name, num_partitions):
    admin_client.create_partitions(topic=topic_name, num_partitions=num_partitions)

def alter_topic_configs(admin_client, topic_name, configurations):
    admin_client.alter_configs(resource_type='topic', resource_name=topic_name, configs=configurations)

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--bootstrap_servers", help="Bootstrap servers for the Kafka Admin Client")
    parser.add_argument("--topic_name", help="Name of the topic")
    parser.add_argument("--partitions", type=int, help="Number of partitions for the topic")
    parser.add_argument("--replication_factor", type=int, help="Replication factor for the topic")
    parser.add_argument("--configs", help="A dictionary of configurations for the topic")
    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers)

    if args.partitions:
        if args.topic_name:
            create_topic(admin_client, args.topic_name, args.partitions, args.replication_factor, args.configs)
        else:
            increase_partition(admin_client, args.topic_name, args.partitions)
            
    if args.configs and args.topic_name:
        alter_topic_configs(admin_client, args.topic_name, args.configs)

if __name__ == "__main__":
    main()